final_sva:
property p_bad4;
  @(posedge PCLK) (PSEL == 1'b1) |=>=> (PREADY == 1'b1);
endproperty
assert property (p_bad4);

property p_bad1;
  @(posedge PCLK) (PSEL && PENABLE) |-> (PRDATA == PWDATA)
endproperty
assert property (p_bad1);

property p_bad2;
  @(posedge PCLK) ((PSEL && PENABLE) |-> (PRDATA == PWDATA);
endproperty
assert property (p_bad2);

property p_ok;
  @(posedge PCLK) (PSEL && PENABLE) |-> ##1 (PREADY == 1'b1);
endproperty
assert property (p_ok);
